from kafka import KafkaConsumer
import json

# Define your message handlers
def handle_transaction(message):
    # Implement your business logic here
    print(f"Processing transaction: {message}")

def handle_alert(message):
    # Implement your alert handling logic here
    print(f"Handling alert: {message}")

# Create a dictionary to map message types to handlers
message_handlers = {
    'transaction': handle_transaction,
    'alert': handle_alert
}

# Kafka consumer configuration
consumer_config = {
    'bootstrap_servers': ['localhost:9092'],
    'group_id': 'financial_transactions_group'
}

# Topics to consume
topics = ['transactions', 'alerts']

# Create Kafka consumer
consumer = KafkaConsumer(*topics, **consumer_config)

print("Kafka Consumer started. Listening for messages...")

for message in consumer:
    # Deserialize the message value
    try:
        message_value = json.loads(message.value.decode('utf-8'))
        message_type = message_value.get('type')
        
        if message_type and message_type in message_handlers:
            # Execute the appropriate handler
            handler = message_handlers[message_type]
            handler(message_value)
        else:
            print(f"Unknown message type: {message_type}")
    except Exception as e:
        print(f"Error processing message: {e}")

consumer.close()